import React, { useEffect, useState } from "react";
import API from "../../api/api";

const AdminDashboard = () => {
  const user = JSON.parse(localStorage.getItem("user") || "{}");

  const [stats, setStats]       = useState({ users: 0, projects: 0, proposals: 0, freelancers: 0, clients: 0 });
  const [projects, setProjects] = useState([]);
  const [allUsers, setAllUsers] = useState([]);
  const [loading, setLoading]   = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        // ✅ Get stats from admin/dashboard (has freelancers + clients count)
        const statsRes = await API.get("/admin/dashboard");
        setStats(statsRes.data || {});

        // ✅ Get projects with client_name
        const projRes = await API.get("/projects");
        setProjects(projRes.data || []);

        // ✅ Get users for PDF
        const usersRes = await API.get("/users");
        setAllUsers(usersRes.data || []);

      } catch (err) {
        console.error("Admin dashboard error:", err);
      }
      setLoading(false);
    };
    load();
  }, []);

  // ✅ Generate PDF using jsPDF CDN
  const generatePDF = (todayOnly = false) => {
    const loadAndBuild = () => buildPDF(todayOnly);
    if (!window.jspdf) {
      const script = document.createElement("script");
      script.src = "https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js";
      script.onload = loadAndBuild;
      document.head.appendChild(script);
    } else {
      loadAndBuild();
    }
  };

  const buildPDF = (todayOnly) => {
    const { jsPDF } = window.jspdf;
    const doc  = new jsPDF();
    const today = new Date().toLocaleDateString("en-IN", { day: "2-digit", month: "long", year: "numeric" });
    const now   = new Date().toLocaleTimeString("en-IN");

    // HEADER
    doc.setFillColor(15, 118, 110);
    doc.rect(0, 0, 210, 28, "F");
    doc.setTextColor(255, 255, 255);
    doc.setFontSize(18);
    doc.setFont("helvetica", "bold");
    doc.text("FreelanceHub", 14, 12);
    doc.setFontSize(10);
    doc.setFont("helvetica", "normal");
    doc.text(todayOnly ? "Today's Login Report" : "Full Platform Report", 14, 21);
    doc.text(`Generated: ${today} ${now}`, 196, 21, { align: "right" });
    doc.setTextColor(0, 0, 0);

    let y = 38;

    if (!todayOnly) {
      // STATS SECTION
      doc.setFontSize(13); doc.setFont("helvetica", "bold");
      doc.text("Platform Statistics", 14, y); y += 8;

      const statsRows = [
        ["Total Users",      stats.users      || 0],
        ["Freelancers",      stats.freelancers || 0],
        ["Clients",          stats.clients     || 0],
        ["Total Projects",   stats.projects    || 0],
        ["Total Proposals",  stats.proposals   || 0],
      ];
      doc.setFontSize(10); doc.setFont("helvetica", "normal");
      statsRows.forEach(([label, val], i) => {
        if (i % 2 === 0) { doc.setFillColor(240, 253, 250); doc.rect(14, y - 4, 90, 8, "F"); }
        doc.text(label, 16, y);
        doc.setFont("helvetica", "bold"); doc.text(String(val), 90, y);
        doc.setFont("helvetica", "normal"); y += 10;
      });
      y += 5;

      // PROJECTS TABLE
      doc.setFontSize(13); doc.setFont("helvetica", "bold");
      doc.text("Project Details", 14, y); y += 8;
      doc.setFillColor(15, 118, 110); doc.rect(14, y - 5, 182, 8, "F");
      doc.setTextColor(255, 255, 255); doc.setFontSize(9);
      doc.text("Title", 16, y); doc.text("Status", 80, y);
      doc.text("Budget", 115, y); doc.text("Client", 150, y); doc.text("Proposals", 180, y);
      y += 6; doc.setTextColor(0, 0, 0); doc.setFont("helvetica", "normal");

      projects.forEach((p, i) => {
        if (y > 270) { doc.addPage(); y = 20; }
        if (i % 2 === 0) { doc.setFillColor(248, 250, 252); doc.rect(14, y - 4, 182, 8, "F"); }
        doc.text((p.title || "").slice(0, 30), 16, y);
        doc.text(p.status || "open", 80, y);
        doc.text(`Rs.${p.budget}`, 115, y);
        doc.text((p.client_name || "—").slice(0, 18), 150, y);
        doc.text(String(p.proposals_count || 0), 185, y);
        y += 9;
      });
      y += 8;

      // USERS TABLE
      if (y > 240) { doc.addPage(); y = 20; }
      doc.setFontSize(13); doc.setFont("helvetica", "bold");
      doc.text("Registered Users", 14, y); y += 8;
      doc.setFillColor(15, 118, 110); doc.rect(14, y - 5, 182, 8, "F");
      doc.setTextColor(255, 255, 255); doc.setFontSize(9);
      doc.text("Name", 16, y); doc.text("Email", 70, y); doc.text("Role", 170, y);
      y += 6; doc.setTextColor(0, 0, 0); doc.setFont("helvetica", "normal");

      allUsers.filter(u => u.role !== "admin").forEach((u, i) => {
        if (y > 270) { doc.addPage(); y = 20; }
        if (i % 2 === 0) { doc.setFillColor(248, 250, 252); doc.rect(14, y - 4, 182, 8, "F"); }
        doc.text((u.name || "").slice(0, 28), 16, y);
        doc.text((u.email || "").slice(0, 38), 70, y);
        doc.text(u.role || "—", 170, y);
        y += 9;
      });

    } else {
      // TODAY'S LOGIN REPORT
      doc.setFontSize(13); doc.setFont("helvetica", "bold");
      doc.text(`All Registered Users — ${today}`, 14, y); y += 8;
      doc.setFillColor(15, 118, 110); doc.rect(14, y - 5, 182, 8, "F");
      doc.setTextColor(255, 255, 255); doc.setFontSize(9);
      doc.text("Name", 16, y); doc.text("Email", 70, y); doc.text("Role", 170, y);
      y += 6; doc.setTextColor(0, 0, 0); doc.setFont("helvetica", "normal");

      allUsers.forEach((u, i) => {
        if (y > 270) { doc.addPage(); y = 20; }
        if (i % 2 === 0) { doc.setFillColor(248, 250, 252); doc.rect(14, y - 4, 182, 8, "F"); }
        doc.text((u.name || "").slice(0, 28), 16, y);
        doc.text((u.email || "").slice(0, 38), 70, y);
        doc.text(u.role || "—", 170, y);
        y += 9;
      });
    }

    // FOOTER
    const pages = doc.internal.getNumberOfPages();
    for (let i = 1; i <= pages; i++) {
      doc.setPage(i);
      doc.setFontSize(8); doc.setTextColor(150);
      doc.text(`FreelanceHub — Confidential  |  Page ${i} of ${pages}`, 14, 290);
    }

    doc.save(todayOnly ? `login-report-${today}.pdf` : `freelancehub-report-${today}.pdf`);
  };

  if (loading) return <div className="text-center py-16 text-gray-400">Loading...</div>;

  return (
    <div className="bg-white min-h-screen p-8">
      <div className="max-w-5xl mx-auto">

        <h1 className="text-3xl font-bold text-gray-800 mb-8">Admin Dashboard</h1>

        {/* STAT CARDS */}
        <div className="grid grid-cols-3 gap-6 mb-8">
          {[
            { label: "Clients",     value: stats.clients     || 0, color: "text-blue-600"   },
            { label: "Freelancers", value: stats.freelancers || 0, color: "text-green-600"  },
            { label: "Projects",    value: stats.projects    || 0, color: "text-purple-600" },
          ].map((s, i) => (
            <div key={i} className="bg-white border border-gray-200 rounded-xl p-8 text-center shadow-sm">
              <p className={`text-5xl font-bold ${s.color}`}>{s.value}</p>
              <p className="text-gray-500 mt-3 text-lg">{s.label}</p>
            </div>
          ))}
        </div>

        {/* PROJECT DETAILS TABLE */}
        <div className="bg-white border border-gray-200 rounded-xl shadow-sm">
          <div className="p-5 border-b border-gray-100">
            <h2 className="text-xl font-bold text-gray-700">Project Details</h2>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead className="bg-gray-50 border-b border-gray-100">
                <tr>
                  <th className="text-left px-5 py-3 text-gray-500 font-medium">Title</th>
                  <th className="text-left px-5 py-3 text-gray-500 font-medium">Status</th>
                  <th className="text-left px-5 py-3 text-gray-500 font-medium">Budget</th>
                  <th className="text-left px-5 py-3 text-gray-500 font-medium">Client</th>
                  <th className="text-left px-5 py-3 text-gray-500 font-medium">Proposals</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {projects.length === 0 ? (
                  <tr><td colSpan={5} className="text-center py-8 text-gray-400">No projects yet.</td></tr>
                ) : projects.map((p, i) => (
                  <tr key={i} className="hover:bg-gray-50 transition">
                    <td className="px-5 py-3 font-medium text-gray-800">{p.title}</td>
                    <td className="px-5 py-3">
                      <span className={`px-2 py-0.5 rounded-full text-xs font-semibold capitalize ${
                        p.status === "closed" ? "bg-red-100 text-red-600" : "bg-green-100 text-green-600"
                      }`}>{p.status || "Open"}</span>
                    </td>
                    <td className="px-5 py-3 text-gray-600">₹{p.budget}</td>
                    <td className="px-5 py-3 text-gray-600">{p.client_name || "—"}</td>
                    <td className="px-5 py-3 text-gray-600">{p.proposals_count || 0}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* PDF BUTTONS */}
          <div className="p-5 border-t border-gray-100 flex gap-3">
            <button onClick={() => generatePDF(false)}
              className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-lg text-sm font-medium transition">
              📄 Generate Full PDF Report
            </button>
            <button onClick={() => generatePDF(true)}
              className="flex items-center gap-2 bg-green-600 hover:bg-green-700 text-white px-5 py-2.5 rounded-lg text-sm font-medium transition">
              📊 Generate Today's Login Report
            </button>
          </div>
        </div>

      </div>
    </div>
  );
};

export default AdminDashboard;
